//! Topology-driven soft alpha masks: interest planes, multi-scale Betti sieve gates,
//! fused per-pixel alpha + [`TopologyMaskProvenance`] (serde JSON).

#[cfg(test)]
mod tests_internal;

#[cfg(not(target_arch = "wasm32"))]
use gnosis_frf::prelude::*;

/// Discrete Betti-style signature on a super-level-set (mirrors TS `betti-signature.ts`).
#[derive(Clone, Copy, Debug, serde::Serialize, serde::Deserialize, PartialEq)]
pub struct BettiSignature {
    pub beta0: u32,
    pub beta1: u32,
    pub beta2: u32,
    pub euler: i32,
    pub total: u32,
    pub threshold: f32,
}

/// One scale evaluated in [`build_topology_alpha`].
#[derive(Clone, Debug, serde::Serialize, serde::Deserialize, PartialEq)]
pub struct TopologyScaleReport {
    pub scale_index: u32,
    pub plane_width: u32,
    pub plane_height: u32,
    pub signature: BettiSignature,
    pub admissible: bool,
    pub gate: f32,
}

#[derive(Clone, Debug, serde::Serialize, serde::Deserialize, PartialEq)]
pub struct TopologyMaskProvenance {
    pub width: u32,
    pub height: u32,
    pub channels: u32,
    pub scales: Vec<TopologyScaleReport>,
    pub closure_ceiling: f32,
    pub edge_weight: f32,
    pub luma_contrast_weight: f32,
    pub soften_passes: u32,
}

#[derive(Clone, Debug)]
pub struct TopologyAlphaConfig {
    /// Number of dyadic downsamples included (includes full size as scale 0).
    pub num_scales: u32,
    pub threshold_fraction: f32,
    /// Topology closure ceiling (`sig.total <= ceiling`).
    pub closure_ceiling: u32,
    pub edge_weight: f32,
    pub luma_contrast_weight: f32,
    /// Box blur iterations (3×3) on raw alpha field.
    pub soften_passes: u32,
    /// 8-neighbour unions for $\\beta_0$ (matches TS default).
    pub connectivity_8: bool,
}

impl Default for TopologyAlphaConfig {
    fn default() -> Self {
        Self {
            num_scales: 2,
            threshold_fraction: 0.5,
            closure_ceiling: 10,
            edge_weight: 0.85,
            luma_contrast_weight: 0.35,
            soften_passes: 1,
            connectivity_8: true,
        }
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum RgbLayout {
    /// `rgb rgb ...` contiguous, length `width*height*3`
    SequentialRgb,
}

impl RgbLayout {
    #[inline]
    pub fn channel_count(self) -> usize {
        match self {
            RgbLayout::SequentialRgb => 3,
        }
    }
}

/// Builds soft alpha `[0,1]` of length `width*height`.
///
/// Pipeline: luminance → normalized Sobel magnitude + local contrast fuse → multiplied by global
/// per-scale topological gates computed on downsampled luminance super-level sets.
pub fn build_topology_alpha(
    rgb_f32_unit: &[f32],
    width: u32,
    height: u32,
    layout: RgbLayout,
    config: &TopologyAlphaConfig,
) -> Result<(Vec<f32>, TopologyMaskProvenance), String> {
    if width == 0 || height == 0 {
        return Err("topology_mask: zero dimension".into());
    }
    let cn = layout.channel_count();
    let expected = (width as usize)
        .checked_mul(height as usize)
        .and_then(|x| x.checked_mul(cn))
        .ok_or_else(|| "topology_mask: size overflow".to_string())?;
    if rgb_f32_unit.len() != expected {
        return Err(format!(
            "topology_mask: expected {} floats, got {}",
            expected,
            rgb_f32_unit.len()
        ));
    }

    let w = width as usize;
    let h = height as usize;
    let n = w * h;

    let luma = rec709_luma(rgb_f32_unit, layout, w, h);
    let edge = normalized_sobel_magnitude(&luma, w, h);
    let contrast = normalized_local_absdiff(&luma, w, h);

    let mut raw_alpha = vec![0.0_f32; n];

    #[cfg(not(target_arch = "wasm32"))]
    {
        raw_alpha.par_iter_mut().enumerate().for_each(|(i, dst)| {
            let e = edge[i];
            let c = contrast[i];
            let base = config.edge_weight * e + config.luma_contrast_weight * c;
            *dst = base.clamp(0.0, 1.0);
        });
    }
    #[cfg(target_arch = "wasm32")]
    {
        for (i, dst) in raw_alpha.iter_mut().enumerate() {
            let e = edge[i];
            let c = contrast[i];
            let base = config.edge_weight * e + config.luma_contrast_weight * c;
            *dst = base.clamp(0.0, 1.0);
        }
    }

    let mut gates: Vec<f32> = Vec::new();
    let mut scale_reports = Vec::new();

    let max_scales = config.num_scales.max(1);
    for s in 0..max_scales {
        let (lw, lh) = downsized_dims(w, h, s)?;
        let down = subsample_average(&luma, w, h, lw, lh);
        let sig = betti_superlevel_signature(
            &down,
            lw,
            lh,
            config.threshold_fraction,
            config.connectivity_8,
        );
        let admissible = is_closure_admissible_sig(&sig, config.closure_ceiling);
        let gate = if admissible {
            1.0
        } else {
            let over = sig.total.saturating_sub(config.closure_ceiling) as f32 + 1.0;
            (1.0 / over).clamp(0.15, 0.95)
        };
        gates.push(gate);
        scale_reports.push(TopologyScaleReport {
            scale_index: s,
            plane_width: lw as u32,
            plane_height: lh as u32,
            signature: sig,
            admissible,
            gate,
        });
    }

    let combined_gate = gates.into_iter().product::<f32>();

    #[cfg(not(target_arch = "wasm32"))]
    {
        raw_alpha.par_iter_mut().for_each(|a| *a *= combined_gate);
    }
    #[cfg(target_arch = "wasm32")]
    {
        for a in raw_alpha.iter_mut() {
            *a *= combined_gate;
        }
    }

    if config.soften_passes > 0 {
        for _ in 0..config.soften_passes {
            box_blur3_in_place_float(&mut raw_alpha, w, h);
        }
    }

    let mut lo = f32::INFINITY;
    let mut hi = f32::NEG_INFINITY;
    for &v in raw_alpha.iter() {
        lo = lo.min(v);
        hi = hi.max(v);
    }
    let spread = hi - lo;
    if !(spread.is_finite()) || spread <= 1e-8 {
        for a in raw_alpha.iter_mut() {
            *a = combined_gate.clamp(0.0, 1.0);
        }
    } else {
        for a in raw_alpha.iter_mut() {
            *a = ((*a - lo) / spread).clamp(0.0, 1.0);
        }
    }

    let prov = TopologyMaskProvenance {
        width,
        height,
        channels: cn as u32,
        scales: scale_reports,
        closure_ceiling: config.closure_ceiling as f32,
        edge_weight: config.edge_weight,
        luma_contrast_weight: config.luma_contrast_weight,
        soften_passes: config.soften_passes,
    };
    Ok((raw_alpha, prov))
}

#[inline]
fn is_closure_admissible_sig(sig: &BettiSignature, ceiling: u32) -> bool {
    sig.total <= ceiling
}

fn rec709_luma(rgb: &[f32], layout: RgbLayout, w: usize, h: usize) -> Vec<f32> {
    match layout {
        RgbLayout::SequentialRgb => {
            let n = w * h;
            let mut out = Vec::with_capacity(n);
            for i in 0..n {
                let idx = i * 3;
                let r = rgb[idx];
                let g = rgb[idx + 1];
                let b = rgb[idx + 2];
                out.push((0.2126 * r + 0.7152 * g + 0.0722 * b).clamp(0.0, 1.0));
            }
            out
        }
    }
}

#[inline(always)]
fn sample_clamp(luma: &[f32], w: usize, h: usize, x: i32, y: i32) -> f32 {
    let x = x.clamp(0, w as i32 - 1) as usize;
    let y = y.clamp(0, h as i32 - 1) as usize;
    luma[y * w + x]
}

fn normalized_sobel_magnitude(luma: &[f32], w: usize, h: usize) -> Vec<f32> {
    let mut gx = vec![0.0_f32; w * h];
    let mut gy = vec![0.0_f32; w * h];
    for y in 0..h {
        for x in 0..w {
            let xi = x as i32;
            let yi = y as i32;
            let s00 = sample_clamp(luma, w, h, xi - 1, yi - 1);
            let s01 = sample_clamp(luma, w, h, xi - 1, yi);
            let s02 = sample_clamp(luma, w, h, xi - 1, yi + 1);
            let s10 = sample_clamp(luma, w, h, xi, yi - 1);
            let s12 = sample_clamp(luma, w, h, xi, yi + 1);
            let s20 = sample_clamp(luma, w, h, xi + 1, yi - 1);
            let s21 = sample_clamp(luma, w, h, xi + 1, yi);
            let s22 = sample_clamp(luma, w, h, xi + 1, yi + 1);
            // Gx: [-1 0 1; -2 0 2; -1 0 1]
            gx[y * w + x] = (-s00 + s20) + (-2.0 * s01 + 2.0 * s21) + (-s02 + s22);
            // Gy: [-1 -2 -1; 0 0 0; 1 2 1]
            gy[y * w + x] = -s00 - 2.0 * s10 - s20 + s02 + 2.0 * s12 + s22;
        }
    }
    let mut mag = vec![0.0_f32; w * h];
    for i in 0..w * h {
        mag[i] = (gx[i] * gx[i] + gy[i] * gy[i]).sqrt();
    }
    normalize_max_finite(&mag)
}

fn normalized_local_absdiff(luma: &[f32], w: usize, h: usize) -> Vec<f32> {
    let mut v = vec![0.0_f32; w * h];
    for y in 0..h {
        for x in 0..w {
            let c = luma[y * w + x];
            let mut acc = 0.0_f32;
            let mut cnt = 0_u32;
            for (dx, dy) in [(-1, 0), (1, 0), (0, -1), (0, 1)] {
                let n = sample_clamp(luma, w, h, x as i32 + dx, y as i32 + dy);
                acc += (c - n).abs();
                cnt += 1;
            }
            v[y * w + x] = acc / cnt as f32;
        }
    }
    normalize_max_finite(&v)
}

fn normalize_max_finite(v: &[f32]) -> Vec<f32> {
    let mut m = 0.0_f32;
    for &x in v {
        if x.is_finite() {
            m = m.max(x);
        }
    }
    if m <= 1e-12 {
        return vec![0.0_f32; v.len()];
    }
    v.iter().map(|x| (x / m).clamp(0.0, 1.0)).collect()
}

fn downsized_dims(w: usize, h: usize, scale: u32) -> Result<(usize, usize), String> {
    let lw = (w >> scale).max(1);
    let lh = (h >> scale).max(1);
    if lw.checked_mul(lh).is_none() {
        return Err("topology_mask: downsample dims overflow".into());
    }
    Ok((lw, lh))
}

fn subsample_average(src: &[f32], sw: usize, sh: usize, tw: usize, th: usize) -> Vec<f32> {
    let mut out = vec![0.0_f32; tw * th];
    for ty in 0..th {
        let y0 = ty * sh / th;
        let y1 = ((ty + 1) * sh / th).min(sh);
        for tx in 0..tw {
            let x0 = tx * sw / tw;
            let x1 = ((tx + 1) * sw / tw).min(sw);
            let mut sum = 0.0_f32;
            let mut cnt = 0_u32;
            for y in y0..y1 {
                for x in x0..x1 {
                    sum += src[y * sw + x];
                    cnt += 1;
                }
            }
            out[ty * tw + tx] = if cnt > 0 { sum / cnt as f32 } else { 0.0 };
        }
    }
    out
}

fn box_blur3_in_place_float(buf: &mut [f32], w: usize, h: usize) {
    let n = w * h;
    let mut tmp = vec![0.0_f32; n];
    tmp.copy_from_slice(buf);
    for y in 0..h {
        for x in 0..w {
            let mut s = 0.0_f32;
            let mut c = 0_u32;
            for dy in -1_i32..=1 {
                for dx in -1_i32..=1 {
                    let xx = x as i32 + dx;
                    let yy = y as i32 + dy;
                    let v = sample_clamp(&tmp, w, h, xx, yy);
                    s += v;
                    c += 1;
                }
            }
            buf[y * w + x] = s / c as f32;
        }
    }
}

/// Super-level-set Betti proxy (Ts parity target).
pub fn betti_superlevel_signature(
    plane: &[f32],
    width: usize,
    height: usize,
    threshold_fraction: f32,
    connectivity_8: bool,
) -> BettiSignature {
    debug_assert!(width > 0 && height > 0);
    let n = width * height;
    if plane.len() != n || n == 0 {
        return BettiSignature {
            beta0: 0,
            beta1: 0,
            beta2: 0,
            euler: 0,
            total: 0,
            threshold: 0.0,
        };
    }

    let mut max_v = -f32::INFINITY;
    for &v in plane {
        max_v = max_v.max(v);
    }
    if !max_v.is_finite() || max_v <= 0.0 {
        return BettiSignature {
            beta0: 0,
            beta1: 0,
            beta2: 0,
            euler: 0,
            total: 0,
            threshold: 0.0,
        };
    }

    let tf = threshold_fraction.clamp(0.0, 1.0);
    let threshold = tf * max_v;

    let mut mask = vec![false; n];
    let mut v_count: i32 = 0;
    for i in 0..n {
        if plane[i] >= threshold {
            mask[i] = true;
            v_count += 1;
        }
    }
    let v_sz = v_count as usize;

    if v_sz == 0 {
        return BettiSignature {
            beta0: 0,
            beta1: 0,
            beta2: 0,
            euler: 0,
            total: 0,
            threshold,
        };
    }

    let mut dsu = Dsu::new(n);
    for y in 0..height {
        for x in 0..width {
            let i = y * width + x;
            if !mask[i] {
                continue;
            }
            if x + 1 < width && mask[i + 1] {
                dsu.union(i, i + 1);
            }
            if y + 1 < height && mask[i + width] {
                dsu.union(i, i + width);
            }
            if connectivity_8 {
                if x + 1 < width && y + 1 < height && mask[i + width + 1] {
                    dsu.union(i, i + width + 1);
                }
                if x >= 1 && y + 1 < height && mask[i + width - 1] {
                    dsu.union(i, i + width - 1);
                }
            }
        }
    }

    let mut roots = vec![false; n];
    for i in 0..n {
        if mask[i] {
            let r = dsu.find_mut(i);
            roots[r] = true;
        }
    }
    let beta0 = roots.iter().filter(|&&b| b).count() as u32;

    let mut edges = 0_i32;
    for y in 0..height {
        for x in 0..width {
            let i = y * width + x;
            if !mask[i] {
                continue;
            }
            if x + 1 < width && mask[i + 1] {
                edges += 1;
            }
            if y + 1 < height && mask[i + width] {
                edges += 1;
            }
        }
    }

    let mut faces = 0_i32;
    for y in 0..height.saturating_sub(1) {
        for x in 0..width.saturating_sub(1) {
            let i = y * width + x;
            if mask[i] && mask[i + 1] && mask[i + width] && mask[i + width + 1] {
                faces += 1;
            }
        }
    }

    let euler = v_count - edges + faces;

    let mut visited = vec![false; n];
    let mut stack = Vec::<usize>::new();
    for x in 0..width {
        let top = x;
        let bot = (height - 1) * width + x;
        if !mask[top] && !visited[top] {
            visited[top] = true;
            stack.push(top);
        }
        if !mask[bot] && !visited[bot] {
            visited[bot] = true;
            stack.push(bot);
        }
    }
    for y in 0..height {
        let left = y * width;
        let right = y * width + (width - 1);
        if !mask[left] && !visited[left] {
            visited[left] = true;
            stack.push(left);
        }
        if !mask[right] && !visited[right] {
            visited[right] = true;
            stack.push(right);
        }
    }
    while let Some(i) = stack.pop() {
        let x = i % width;
        let y = i / width;
        if x + 1 < width {
            let j = i + 1;
            if !mask[j] && !visited[j] {
                visited[j] = true;
                stack.push(j);
            }
        }
        if x >= 1 {
            let j = i - 1;
            if !mask[j] && !visited[j] {
                visited[j] = true;
                stack.push(j);
            }
        }
        if y + 1 < height {
            let j = i + width;
            if !mask[j] && !visited[j] {
                visited[j] = true;
                stack.push(j);
            }
        }
        if y >= 1 {
            let j = i - width;
            if !mask[j] && !visited[j] {
                visited[j] = true;
                stack.push(j);
            }
        }
    }

    let mut void_ds = Dsu::new(n);
    for y in 0..height {
        for x in 0..width {
            let i = y * width + x;
            if mask[i] || visited[i] {
                continue;
            }
            if x + 1 < width && !mask[i + 1] && !visited[i + 1] {
                void_ds.union(i, i + 1);
            }
            if y + 1 < height && !mask[i + width] && !visited[i + width] {
                void_ds.union(i, i + width);
            }
        }
    }
    let mut void_roots = vec![false; n];
    for i in 0..n {
        if mask[i] || visited[i] {
            continue;
        }
        let r = void_ds.find_mut(i);
        void_roots[r] = true;
    }
    let beta2 = void_roots.iter().filter(|&&b| b).count() as u32;

    let chi = euler;
    let mut beta1 = beta0 as i32 + beta2 as i32 - chi;
    if beta1 < 0 {
        beta1 = 0;
    }

    let total = beta0 + beta2 + beta1 as u32;

    BettiSignature {
        beta0,
        beta1: beta1 as u32,
        beta2,
        euler: chi,
        total,
        threshold,
    }
}

struct Dsu {
    parent: Vec<usize>,
}

impl Dsu {
    fn new(n: usize) -> Self {
        Self {
            parent: (0..n).collect(),
        }
    }

    fn find_mut(&mut self, i: usize) -> usize {
        let mut x = i;
        while self.parent[x] != x {
            x = self.parent[x];
        }
        let root = x;
        let mut y = i;
        while self.parent[y] != y {
            let p = self.parent[y];
            self.parent[y] = root;
            y = p;
        }
        root
    }

    fn union(&mut self, a: usize, b: usize) {
        let ra = self.find_mut(a);
        let rb = self.find_mut(b);
        if ra != rb {
            self.parent[rb] = ra;
        }
    }
}
